```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct LogicalExpressionSnapshot {
    bool initialAnd;
    bool initialOr;
    bool updatedAnd;
    bool updatedOr;
};

/**
 * Function: Demonstrate logical expression builders and operators on reactive values.
 *
 * This function shows how high-level logical operators (`&&`, `||`) compose reactive
 * expressions that are then lifted into `expr` calculations.
 *
 * @param a Initial value for the first boolean input
 * @param b Initial value for the second boolean input
 * @param c Initial value for the fallback boolean input
 * @return LogicalExpressionSnapshot Snapshot of AND/OR results before and after updates
 */
inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    // 1. Create reactive boolean variables using reaction::var
    auto var_a = reaction::var(a);
    auto var_b = reaction::var(b);
    auto var_c = reaction::var(c);

    // 2. Build logical AND expression using && operator
    auto and_expr = var_a && var_b;

    // 3. Build logical OR expression using || operator  
    auto or_expr = var_a || var_c;

    // 4. Use expr to create reactive expressions and get() to get initial values
    auto reactive_and = reaction::expr(and_expr);
    auto reactive_or = reaction::expr(or_expr);

    bool initialAnd = reactive_and.get();
    bool initialOr = reactive_or.get();

    // 5. Update variables using value() method to trigger recomputation
    var_a.value(false);
    var_b.value(true);
    var_c.value(false);

    // 6. Get updated values using get()
    bool updatedAnd = reactive_and.get();
    bool updatedOr = reactive_or.get();

    // 7. Return LogicalExpressionSnapshot with all results
    return LogicalExpressionSnapshot{
        initialAnd,
        initialOr,
        updatedAnd,
        updatedOr
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Reactive Variable Creation**: Used `reaction::var()` to create three reactive boolean variables from the input parameters.

2. **Logical Expression Building**: 
   - Built AND expression using `&&` operator between `var_a` and `var_b`
   - Built OR expression using `||` operator between `var_a` and `var_c`

3. **Reactive Expression Wrapping**: Used `reaction::expr()` to convert the operator expressions into reactive computations.

4. **Value Access**: Used `get()` method to retrieve current values from reactive expressions.

5. **Variable Updates**: Used `value()` method to update the reactive variables, triggering automatic recomputation of dependent expressions.

6. **Result Snapshot**: Returned a `LogicalExpressionSnapshot` struct containing both initial and updated results for both AND/OR expressions.

This implementation demonstrates the core reactive programming pattern where changes to source variables automatically propagate through the dependency graph to update computed expressions.

